#nullable enable // autogenerated

using System.Collections.Generic;
using MukioI18n;
using MVZ2Logic;
using MVZ2Logic.Definitions;
using MVZ2Logic.Localization;
using MVZ2Logic.Options;
using MVZ2Logic.Saves;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.showFPS)]
    public class ShowFPSOptionDropdown : OptionDropdownDefinition
    {
        public ShowFPSOptionDropdown(string nsp, string name) : base(nsp, name)
        {
        }
        public override int GetValue(IOptionContext context)
        {
            return Global.Options.GetFPSMode();
        }
        public override void FillItems(IOptionContext context, List<string> items)
        {
            var localization = Global.Localization;
            items.Add(localization.GetTextParticular(FPS_MODE_DISABLED, LogicStrings.CONTEXT_FPS_MODE));
            items.Add(localization.GetTextParticular(FPS_MODE_TOP_LEFT, LogicStrings.CONTEXT_FPS_MODE));
            items.Add(localization.GetTextParticular(FPS_MODE_TOP_RIGHT, LogicStrings.CONTEXT_FPS_MODE));
            items.Add(localization.GetTextParticular(FPS_MODE_BOTTOM_LEFT, LogicStrings.CONTEXT_FPS_MODE));
            items.Add(localization.GetTextParticular(FPS_MODE_BOTTOM_RIGHT, LogicStrings.CONTEXT_FPS_MODE));
        }
        public override void OnValueChanged(IOptionContext context, int index)
        {
            Global.Options.SetOptionInt(LogicOptionItemID.fpsMode, index);
            Global.Options.SaveOptions();
        }
        [TranslateMsg("FPS模式", LogicStrings.CONTEXT_FPS_MODE)]
        public const string FPS_MODE_DISABLED = "关闭";
        [TranslateMsg("FPS模式", LogicStrings.CONTEXT_FPS_MODE)]
        public const string FPS_MODE_TOP_LEFT = "左上";
        [TranslateMsg("FPS模式", LogicStrings.CONTEXT_FPS_MODE)]
        public const string FPS_MODE_TOP_RIGHT = "右上";
        [TranslateMsg("FPS模式", LogicStrings.CONTEXT_FPS_MODE)]
        public const string FPS_MODE_BOTTOM_LEFT = "左下";
        [TranslateMsg("FPS模式", LogicStrings.CONTEXT_FPS_MODE)]
        public const string FPS_MODE_BOTTOM_RIGHT = "右下";
    }
}
